261	/// A type representing the `tr!` proc macro.
262	pub(crate) struct Tr {
263	    pub msg: Messsage,
264	    pub args: Arguments,
265	    pub locale: Option<Value>,
266	    pub minify_key: bool,
267	    pub minify_key_len: usize,
268	    pub minify_key_prefix: String,
269	    pub minify_key_thresh: usize,
270	}
271	
272	impl Tr {
273	    fn new() -> Self {
274	        Self {
275	            msg: Messsage::default(),
276	            args: Arguments::default(),
277	            locale: None,
278	            minify_key: false,
279	            minify_key_len: DEFAULT_MINIFY_KEY_LEN,
280	            minify_key_prefix: DEFAULT_MINIFY_KEY_PREFIX.into(),
281	            minify_key_thresh: DEFAULT_MINIFY_KEY_THRESH,
282	        }
283	    }
284	
285	    fn parse_minify_key(value: &Value) -> syn::parse::Result<bool> {
286	        if let Value::Expr(Expr::Lit(expr_lit)) = value {
287	            match &expr_lit.lit {
288	                syn::Lit::Bool(lit_bool) => {
289	                    return Ok(lit_bool.value);
290	                }
291	                syn::Lit::Str(lit_str) => {
292	                    let value = lit_str.value();
293	                    if ["true", "false", "yes", "no"].contains(&value.as_str()) {
294	                        return Ok(["true", "yes"].contains(&value.as_str()));
295	                    }
296	                }
297	                _ => {}
298	            }
299	        }
300	        Err(syn::Error::new_spanned(
301	            value,
302	            "`_minify_key` Expected a string literal in `true`, `false`, `yes`, `no`",
303	        ))
304	    }
305	
306	    fn parse_minify_key_len(value: &Value) -> syn::parse::Result<usize> {
307	        if let Value::Expr(Expr::Lit(expr_lit)) = value {
308	            if let syn::Lit::Int(lit_int) = &expr_lit.lit {
309	                return Ok(lit_int.base10_parse().unwrap());
310	            }
311	        }
312	        Err(syn::Error::new_spanned(
313	            value,
314	            "`_minify_key_len` Expected a integer literal",
315	        ))
316	    }
317	
318	    fn parse_minify_key_prefix(value: &Value) -> syn::parse::Result<String> {
319	        if let Value::Expr(Expr::Lit(expr_lit)) = value {
320	            if let syn::Lit::Str(lit_str) = &expr_lit.lit {
321	                return Ok(lit_str.value());
322	            }
323	        }
324	        Err(syn::Error::new_spanned(
325	            value,
326	            "`_minify_key_prefix` Expected a string literal",
327	        ))
328	    }
329	
330	    fn parse_minify_key_thresh(value: &Value) -> syn::parse::Result<usize> {
331	        if let Value::Expr(Expr::Lit(expr_lit)) = value {
332	            if let syn::Lit::Int(lit_int) = &expr_lit.lit {
333	                return Ok(lit_int.base10_parse().unwrap());
334	            }
335	        }
336	        Err(syn::Error::new_spanned(
337	            value,
338	            "`_minify_key_threshold` Expected a integer literal",
339	        ))
340	    }
341	
342	    fn filter_arguments(&mut self) -> syn::parse::Result<()> {
343	        for arg in self.args.iter() {
344	            match arg.name.as_str() {
345	                "locale" => {
346	                    self.locale = Some(arg.value.clone());
347	                }
348	                "_minify_key" => {
349	                    self.minify_key = Self::parse_minify_key(&arg.value)?;
350	                }
351	                "_minify_key_len" => {
352	                    self.minify_key_len = Self::parse_minify_key_len(&arg.value)?;
353	                }
354	                "_minify_key_prefix" => {
355	                    self.minify_key_prefix = Self::parse_minify_key_prefix(&arg.value)?;
356	                }
357	                "_minify_key_thresh" => {
358	                    self.minify_key_thresh = Self::parse_minify_key_thresh(&arg.value)?;
359	                }
360	                _ => {}
361	            }
362	        }
363	
364	        self.args.as_mut().retain(|v| {
365	            ![
366	                "locale",
367	                "_minify_key",
368	                "_minify_key_len",
369	                "_minify_key_prefix",
370	                "_minify_key_thresh",
371	            ]
372	            .contains(&v.name.as_str())
373	        });
374	
375	        Ok(())
376	    }
377	
378	    #[cfg(feature = "log-miss-tr")]
379	    fn log_missing() -> proc_macro2::TokenStream {
380	        quote! {
381	            log::log!(target: "rust-i18n", log::Level::Warn, "missing: {} => {:?} @ {}:{}", msg_key, msg_val, file!(), line!());
382	        }
383	    }
384	
385	    #[cfg(not(feature = "log-miss-tr"))]
386	    fn log_missing() -> proc_macro2::TokenStream {
387	        quote! {}
388	    }
