43	fn remove_quotes(s: &str) -> &str {
44	    let mut start = 0;
45	    let mut end = s.len();
46	    if s.starts_with('"') {
47	        start += 1;
48	    }
49	    if s.ends_with('"') {
50	        end -= 1;
51	    }
52	    &s[start..end]
53	}
