56	fn translate_value_parser(s: &str) -> Result<(String, String), std::io::Error> {
57	    if let Some((key, msg)) = s.split_once("=>") {
58	        let key = remove_quotes(key.trim());
59	        let msg = remove_quotes(msg.trim());
